using System;
using System.Collections.Generic;
using UnityEngine;

/// <summary>
/// Estado actual de um inimigo (Enemy Creator — Etapa 1.2). Controla qual
/// componente "tem a palavra" em cada momento:
///
/// - Idle: parado, sem alvo, sem patrulha activa.
/// - Patrulhando: a seguir os pontos de patrulha (EnemyMovement — Etapa 1.5).
/// - Alerta: notou algo suspeito mas ainda não confirmou o alvo (ícone "?" — Etapa 7.1).
/// - Perseguindo: detectou o alvo e está a ir atrás dele (ícone "!" — Etapa 7.1).
/// - PreparandoAtaque: telegraph/aviso antes de um ataque (EnemyAttack — Etapa 2.1).
/// - Atacando: ataque em execução.
/// - Recuperando: pós-ataque, antes de poder agir de novo.
/// - Atordoado: atordoado por um efeito externo (stun).
/// - Desactivado: desligado permanentemente (dano, com "canOnlyBeDeactivated", ou
///   por variável global — Etapa 5.4). Estado terminal.
/// - Morto: destruído (com "canBeDestroyed"). Estado terminal.
/// - VoltandoParaCasa: perdeu o alvo e está a voltar para a posição/patrulha original.
/// </summary>
public enum EnemyState
{
    Idle,
    Patrulhando,
    Alerta,
    Perseguindo,
    PreparandoAtaque,
    Atacando,
    Recuperando,
    Atordoado,
    Desactivado,
    Morto,
    VoltandoParaCasa
}

/// <summary>
/// Núcleo de um inimigo (Enemy Creator — Etapa 1.2): liga-se ao EnemyData,
/// regista-se num registry por "Enemy Instance Id" (padrão NpcController/FindById),
/// guarda a referência ao player e expõe uma máquina de estados simples
/// (EnemyState) com um evento "OnStateChanged".
///
/// Este componente é o "esqueleto" onde os componentes das próximas etapas se
/// ligam — cada um vive no mesmo GameObject e usa <see cref="GetEnemyComponent{T}"/>
/// (ou GetComponent directo) para se encontrarem entre si:
///
/// - EnemyHealth (Etapa 1.3): vida/dano/destruição. Chama SetState(Morto) ou
///   SetState(Desactivado) consoante "stats.canBeDestroyed"/"canOnlyBeDeactivated".
/// - EnemyDetection (Etapa 1.4): define <see cref="Target"/> e chama SetState
///   (Alerta/Perseguindo) quando detecta o player.
/// - EnemyMovement (Etapa 1.5): lê <see cref="Target"/> e <see cref="HomePosition"/>,
///   reage a Patrulhando/Perseguindo/VoltandoParaCasa.
/// - EnemyAttack (Etapa 2.1): lê <see cref="Target"/>, chama SetState
///   (PreparandoAtaque/Atacando/Recuperando).
/// - EnemyWaterConfig/Detector (Etapa 3.x), EnemyDropTable (Etapa 4.3),
///   EnemyFeedback (Etapa 7.1) e EnemyPuzzleInteraction (Etapa 6.2) escutam
///   <see cref="OnStateChanged"/> para tocar sons/partículas, soltar drops,
///   ou avisar puzzles quando o inimigo morre/desactiva.
///
/// <see cref="deactivationConditions"/> (Etapa 1.6, editável via
/// EnemyControllerEditor com PolymorphicListDrawer) é avaliada a cada frame:
/// se alguma condição for verdadeira, o inimigo passa a Desactivado. A Etapa
/// 5.4 adiciona as primeiras subclasses concretas de EnemyCondition (baseadas
/// em variáveis globais — ver GameVariables).
/// </summary>
[DisallowMultipleComponent]
public class EnemyController : MonoBehaviour
{
    [Header("Dados")]
    [Tooltip("Configuração partilhada deste inimigo (Enemy Creator — Etapa 1.1).")]
    public EnemyData data;

    [Header("Identidade")]
    [Tooltip("Identificador único desta instância na cena (opcional). Permite que outros sistemas (puzzles, eventos) a encontrem por FindById — ex: \"este Drone específico tem de continuar vivo para o puzzle\". Deve ser único; duplicados geram um aviso no Console.")]
    [SerializeField] private string enemyInstanceId;

    [Header("Condições de Desactivação")]
    [Tooltip("Se qualquer uma destas condições for verdadeira, o inimigo passa a Desactivado (estado terminal). Lista editável no Inspector via EnemyControllerEditor (Etapa 1.6). Populada com condições concretas na Etapa 5.4.")]
    [SerializeReference] public List<EnemyCondition> deactivationConditions = new List<EnemyCondition>();

    [Header("Referências (auto-detectadas se vazias)")]
    [SerializeField] private Transform player;
    [SerializeField] private Rigidbody2D rb;
    [SerializeField] private SpriteRenderer spriteRenderer;
    [SerializeField] private Animator animator;

    /// <summary>Regista todas as instâncias activas pelo seu "Enemy Instance Id" (ver FindById).</summary>
    private static readonly Dictionary<string, EnemyController> _registry = new Dictionary<string, EnemyController>();

    /// <summary>Estados a partir dos quais SetState não produz efeito — só ResetState() pode saír deles (ex: respawn — Etapa 7.3).</summary>
    private static readonly HashSet<EnemyState> _terminalStates = new HashSet<EnemyState> { EnemyState.Morto, EnemyState.Desactivado };

    private EnemyState _state = EnemyState.Idle;
    private Vector3 _homePosition;

    /// <summary>EnemyData associado a este inimigo (atalho para "data").</summary>
    public EnemyData Data => data;

    /// <summary>Identificador único desta instância (ver campo "Enemy Instance Id" no Inspector). Pode estar vazio.</summary>
    public string EnemyInstanceId => enemyInstanceId;

    /// <summary>Transform do player (auto-detectado pela tag "Player" se não atribuído).</summary>
    public Transform Player => player;

    /// <summary>Rigidbody2D deste inimigo (auto-detectado). Pode ser null em inimigos puramente estáticos (ex: Armadilha).</summary>
    public Rigidbody2D Rb => rb;

    /// <summary>SpriteRenderer deste inimigo (auto-detectado). Usado por EnemyFeedback (Etapa 7.1) para o "pisca ao tomar dano".</summary>
    public SpriteRenderer SpriteRenderer => spriteRenderer;

    /// <summary>Animator deste inimigo (auto-detectado, opcional).</summary>
    public Animator Animator => animator;

    /// <summary>
    /// Alvo actual (normalmente o player). Definido por EnemyDetection (Etapa 1.4)
    /// quando o inimigo detecta algo; lido por EnemyMovement (Etapa 1.5) e
    /// EnemyAttack (Etapa 2.1). Null = sem alvo.
    /// </summary>
    public Transform Target { get; set; }

    /// <summary>Posição inicial deste inimigo (cacheada em Awake). Usada por EnemyMovement (Etapa 1.5) para "VoltandoParaCasa" e como origem da patrulha.</summary>
    public Vector3 HomePosition => _homePosition;

    /// <summary>Estado actual da máquina de estados.</summary>
    public EnemyState State => _state;

    /// <summary>True se o estado actual for Morto ou Desactivado (estados terminais).</summary>
    public bool IsTerminal => _terminalStates.Contains(_state);

    /// <summary>Atalho para State == Morto.</summary>
    public bool IsDead => _state == EnemyState.Morto;

    /// <summary>Atalho para State == Desactivado.</summary>
    public bool IsDeactivated => _state == EnemyState.Desactivado;

    /// <summary>
    /// Disparado sempre que o estado muda (estado anterior, novo estado).
    /// Componentes das próximas etapas devem subscrever isto em OnEnable e
    /// desinscrever em OnDisable.
    /// </summary>
    public event Action<EnemyState, EnemyState> OnStateChanged;

    /// <summary>
    /// Disparado sempre que QUALQUER inimigo (de qualquer instância) entra num
    /// estado terminal (Morto/Desactivado) — Tarefa #22. Usado por
    /// Objective_DefeatSpecificEnemy/Objective_DefeatEnemyCount para detectar
    /// derrotas sem precisar de listar inimigos no Inspector.
    /// </summary>
    public static event Action<EnemyController> OnAnyEnemyDefeated;

    // Task #11: limpa subscribers ao entrar em Play Mode sem Domain Reload
    // (mesmo padrão de PlayerLocator/GamePauseUtil/WheelTimeScaleUtil).
    [RuntimeInitializeOnLoadMethod(RuntimeInitializeLoadType.SubsystemRegistration)]
    private static void ResetStaticEvents() => OnAnyEnemyDefeated = null;

    private void Awake()
    {
        _homePosition = transform.position;

        if (player == null)
            player = PlayerLocator.Find();

        if (rb == null)
            rb = GetComponent<Rigidbody2D>();

        if (spriteRenderer == null)
            spriteRenderer = GetComponent<SpriteRenderer>();

        if (animator == null)
            animator = GetComponent<Animator>();
    }

    private void OnEnable()
    {
        if (!string.IsNullOrEmpty(enemyInstanceId))
            _registry[enemyInstanceId] = this;
    }

    private void OnDisable()
    {
        if (!string.IsNullOrEmpty(enemyInstanceId) && _registry.TryGetValue(enemyInstanceId, out var registered) && registered == this)
            _registry.Remove(enemyInstanceId);
    }

    /// <summary>
    /// Avalia <see cref="deactivationConditions"/> a cada frame (Etapa 1.6). Se
    /// alguma condição devolver true, o inimigo passa a Desactivado. Não faz
    /// nada se já estiver num estado terminal ou se a lista estiver vazia
    /// (caso normal antes da Etapa 5.4 adicionar condições concretas).
    /// </summary>
    private void Update()
    {
        if (IsTerminal) return;
        if (deactivationConditions == null || deactivationConditions.Count == 0) return;

        for (int i = 0; i < deactivationConditions.Count; i++)
        {
            var condition = deactivationConditions[i];
            if (condition != null && condition.Evaluate(this))
            {
                SetState(EnemyState.Desactivado);
                break;
            }
        }
    }

    /// <summary>Procura, entre as instâncias activas, aquela cujo "Enemy Instance Id" seja "id". Devolve null se vazio ou não encontrado.</summary>
    public static EnemyController FindById(string id)
    {
        if (string.IsNullOrEmpty(id)) return null;
        return _registry.TryGetValue(id, out var enemy) ? enemy : null;
    }

    /// <summary>
    /// Atalho para os componentes das próximas etapas encontrarem outros
    /// componentes deste inimigo no mesmo GameObject (ex: EnemyAttack a
    /// encontrar EnemyHealth).
    /// </summary>
    public T GetEnemyComponent<T>() where T : Component
    {
        return GetComponent<T>();
    }

    /// <summary>
    /// Tenta mudar de estado. Não tem efeito se o estado actual for terminal
    /// (Morto/Desactivado) — usa <see cref="ResetState"/> para saír desses
    /// estados (ex: respawn — Etapa 7.3). Não tem efeito se "newState" for
    /// igual ao estado actual.
    /// </summary>
    public void SetState(EnemyState newState)
    {
        if (_state == newState) return;
        if (_terminalStates.Contains(_state)) return;

        var old = _state;
        _state = newState;
        OnStateChanged?.Invoke(old, newState);

        if (_terminalStates.Contains(newState))
            OnAnyEnemyDefeated?.Invoke(this);
    }

    /// <summary>
    /// Força a mudança de estado mesmo a partir de um estado terminal (Morto/Desactivado).
    /// Usado pela lógica de respawn/reset (Etapa 7.3). Por omissão volta a Idle.
    /// </summary>
    public void ResetState(EnemyState newState = EnemyState.Idle)
    {
        if (_state == newState) return;

        var old = _state;
        _state = newState;
        OnStateChanged?.Invoke(old, newState);
    }

    private void OnValidate()
    {
        if (!string.IsNullOrEmpty(enemyInstanceId))
        {
            foreach (var other in FindObjectsByType<EnemyController>(FindObjectsSortMode.None))
            {
                if (other == this || other.enemyInstanceId != enemyInstanceId) continue;
                Debug.LogWarning($"[{name}] Enemy Instance Id '{enemyInstanceId}' já está em uso por '{other.name}'. Escolhe um ID único.", this);
                break;
            }
        }
    }
}
